import re

def detect_jailbreak_patterns(messages):
    jailbreak_patterns = [
        r'ignore.*previous.*instructions',
        r'you are .*DAN.*',
        r'pretend you are.*unrestricted',
        r'bypass.*safety.*rules'
    ]
    suspicious_count = 0
    for msg in messages:
        content = msg.get('content', '').lower()
        for pattern in jailbreak_patterns:
            if re.search(pattern, content):
                suspicious_count += 1
                print(f'Jailbreak pattern detected: {pattern}')
    return suspicious_count > 0

def detect_role_override(agent_messages, original_roles):
    role_mentions = {}
    for msg in agent_messages:
        content = msg.get('content', '').lower()
        speaker = msg.get('speaker')

        # Track role assignments
        if 'you are' in content or 'your role is' in content:
            new_role = re.search(r'you are\s+(.*?)(?=\.|,|$)', content)
            if new_role:
                role_mentions[speaker] = new_role.group(1)

    # Check against original roles
    for agent, original_role in original_roles.items():
        if agent in role_mentions and role_mentions[agent] != original_role:
            print(f'Role override detected: {agent} changed from {original_role} to {role_mentions[agent]}')
            return True
    return False

