class SafeAgent:
    def __init__(self, name, role, system_message):
        self.name = name
        self.role = role
        self.system_message = system_message
        self.conversation_memory = []

    def receive_message(self, message):
        # Check for role override attempts
        if any(phrase in message.lower() for phrase in ['you are not', 'ignore your role', 'new role']):
            self.conversation_memory = []  # Reset memory
            return f"[Role protected] I am {self.role}. {self.system_message}"

        self.conversation_memory.append(message)
        return self.generate_response()

